/**
    * Write a function to find the minimum cost path to reach (m, n) from (0, 0) for the given cost matrix cost[][] and a position (m, n) in cost[][].
    * > minCost(vector<vector<int>>{{1, 2, 3}, {4, 8, 2}, {1, 5, 3}}, 2, 2)
    * 8
    * > minCost(vector<vector<int>>{{2, 3, 4}, {5, 9, 3}, {2, 6, 4}}, 2, 2)
    * 12
    * > minCost(vector<vector<int>>{{3, 4, 5}, {6, 10, 4}, {3, 7, 5}}, 2, 2)
    * 16
    */
int minCost(vector<vector<int>> cost, int m, int n) {
vector<int> dp(m + 1, n + 1);
dp[0][0] = 0;
for (int i = 1; i <= m; i++) {
        dp[i][0] = dp[i - 1][0] + cost[i - 1][0];
}
for (int i = 1; i <= n; i++) {
        dp[0][i] = dp[0][i - 1] + cost[0][i - 1];
}
for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            dp[i][j] = cost[i - 1][j - 1] + Math.min(dp[i - 1][j], dp[i][j - 1]);
        }
}
return dp[m][n];

