/**
    * Write a function to get the n smallest items from a dataset.
    * > smallNnum(vector<int>{10, 20, 50, 70, 90, 20, 50, 40, 60, 80, 100}, 2)
    * {10, 20}
    * > smallNnum(vector<int>{10, 20, 50, 70, 90, 20, 50, 40, 60, 80, 100}, 5)
    * {10, 20, 20, 40, 50}
    * > smallNnum(vector<int>{10, 20, 50, 70, 90, 20, 50, 40, 60, 80, 100}, 3)
    * {10, 20, 20}
    */
vector<int> smallNnum(vector<int> list1, int n) {
        vector<int> smallN = vector<int>();
        int k = 0;
        int i;
        for (i = 0; i < n; i++) {
            int min = list1[i];
            int index = i;
            for (int j = i + 1; j < list1.size(); j++) {
                if (min > list1[j]) {
                    index = j;
                    min = list1[j];
                }
            }
            smallN.push_back(min);
            list1[index] = list1[i];
            list1[i] = min;
            k++;
        }
        return smallN;
}

