        * [10, 20, 20]
        */
    public static List<Integer> smallNnum(List<Integer> list1, int n) {
            if (list1 == null || list1.size() < n)
                return null;
            if (list1.size() == 0)
                return list1;

            List<Integer> list2 = new ArrayList<>(list1);
            Collections.sort(list2);

            return list2.subList(0, n);
    }
}

