/**
    * Write a function to sort each sublist of strings in a given list of lists using lambda function.
    * > sortSublists(vector<vector<string>>{{string("green"), string("orange")}, {string("black"), string("white")}, {string("white"), string("black"), string("orange")}})
    * {{string("green"), string("orange")}, {string("black"), string("white")}, {string("black"), string("orange"), string("white")}}
    * > sortSublists(vector<vector<string>>{{string(" red "), string("green")}, {string("blue "), string(" black")}, {string(" orange"), string("brown")}})
    * {{string(" red "), string("green")}, {string(" black"), string("blue ")}, {string(" orange"), string("brown")}}
