def count_Hexadecimal(L,R) :
    """
    Write a python function to count hexadecimal numbers for a given range.
    >>> count_Hexadecimal(10,15)
    6
    >>> count_Hexadecimal(2,4)
    0
    >>> count_Hexadecimal(15,16)
    1
    """
