/**
    * Write a function to find common elements in given nested lists. * list item * list item * list item * list item
    * > commonInNestedLists(vector<vector<int>>{{12, 18, 23, 25, 45}, {7, 12, 18, 24, 28}, {1, 5, 8, 12, 15, 16, 18}})
    * {18, 12}
    * > commonInNestedLists(vector<vector<int>>{{12, 5, 23, 25, 45}, {7, 11, 5, 23, 28}, {1, 5, 8, 18, 23, 16}})
    * {5, 23}
    * > commonInNestedLists(vector<vector<int>>{{2, 3, 4, 1}, {4, 5}, {6, 4, 8}, {4, 5}, {6, 8, 4}})
    * {4}
    */
vector<int> commonInNestedLists(vector<vector<int>> nestedlist) {
        vector<int> result;
        int i;
        int j;
        int k;
        int n;
        int m;
        int temp;

        n = nestedlist.size();
        m = nestedlist[0].size();
        result = 0;

        for (i = 0; i < n; i++) {
            for (j = 0; j < m; j++) {
                temp = nestedlist[i][j];
                k = 1;
                while (k < m) {
                    if (nestedlist[i][k] != temp) {
                        break;
                    }
                    k++;
                }
                if (k == m) {
                    result = temp;
                    break;
                }
            }
        }
        return result;
}

