/**
    * Write a function to assign frequency to each tuple in the given tuple list.
    * > assignFreq(vector<vector<int>>{{6, 5, 8}, {2, 7}, {6, 5, 8}, {6, 5, 8}, {9}, {2, 7}})
    * string("[(6, 5, 8, 3), (2, 7, 2), (9, 1)]")
    * > assignFreq(vector<vector<int>>{{4, 2, 4}, {7, 1}, {4, 8}, {4, 2, 4}, {9, 2}, {7, 1}})
    * string("[(4, 2, 4, 2), (7, 1, 2), (4, 8, 1), (9, 2, 1)]")
    * > assignFreq(vector<vector<int>>{{11, 13, 10}, {17, 21}, {4, 2, 3}, {17, 21}, {9, 2}, {4, 2, 3}})
    * string("[(11, 13, 10, 1), (17, 21, 2), (4, 2, 3, 2), (9, 2, 1)]")
    */
string assignFreq(vector<vector<int>> testList) {
        string result = "[";
        for (auto v : testList) {
            result += "(";
            for (auto i : v) {
                result += i + ", ";
            }
            result = result.slice(0, -2);
            result += "), ";
        }
        result = result.slice(0, -2);
        result += "]";
        return result;
}

