    3
    >>> longest_subseq_with_diff_one([1, 2, 3, 2, 3, 7, 2, 1], 8)
    7
    """
    dp = [1 for i in range(n)]
    for i in range(n):
        for j in range(i):
            if ((arr[i] == arr[j]+1) or (arr[i] == arr[j]-1)):
                dp[i] = max(dp[i], dp[j]+1)
    result = 1
    for i in range(n):
        if (result < dp[i]):
            result = dp[i]
    return result

